int array_all_less_than_k(int n, int *a, int k)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      ((__return == 1 &&
        (forall (i: Z), (0 <= i && i < n) => l[i] < k)) ||
       (__return == 0 &&
        (exists i, 0 <= i && i < n && l[i] >= k))) &&
      IntArray::full(a, n, l)
*/
{
    int i;

    /*@ Inv
          0 <= i && i <= n &&
          a == a@pre &&
          n == n@pre &&
          k == k@pre &&
          (forall (j: Z), (0 <= j && j < i) => l[j] < k) &&
          IntArray::full(a, n, l)
    */
    for (i = 0; i < n; ++i) {
        if (a[i] >= k) {
            return 0;
        }
    }

    /*@ Assert
          i == n &&
          a == a@pre &&
          n == n@pre &&
          k == k@pre &&
          (forall (j: Z), (0 <= j && j < n) => l[j] < k) &&
          IntArray::full(a, n, l)
    */
    return 1;
}
